import json

import files
import llm_client
import messages
import prompts
import protocol
import safety
import session
import shell
import tools


def _execute_tool_call(parsed):
    """Execute a parsed tool call dict. Returns a string result for the LLM.

    Raises RuntimeError on critical failures.
    """
    tool_name = parsed.get("tool")
    arguments = parsed.get("arguments") or {}

    allowed_tools = {
        "list_files": tools.list_files_tool,
        "read_file": tools.read_file_tool,
        "search_text": tools.search_text_tool,
        "write_file": tools.write_file_tool,
        "run_shell": tools.run_shell_tool,
    }

    if tool_name not in allowed_tools:
        return json.dumps({"ok": False, "error": f"unknown tool: {tool_name}"})

    if tool_name in ("write_file", "run_shell"):
        if not safety.confirm_tool_call(tool_name, arguments):
            return json.dumps({"ok": False, "error": "user denied confirmation"})

    try:
        result = allowed_tools[tool_name](arguments)
        return json.dumps(result)
    except Exception as exc:
        return json.dumps({"ok": False, "error": str(exc)})


def run_agent(settings, initial_message, session_id=None, chat_mode=False):
    """Run the agent loop for a given user message.

    Returns on completion. In chat_mode the loop stays open for more messages.
    """
    sess = session.load_or_create(session_id)
    user_msg = {"role": "user", "content": initial_message}
    if not chat_mode:
        sess = session.append_message(sess, user_msg)

    system_prompt = prompts.build_system_prompt()
    contexts = [{"role": "system", "content": system_prompt}]

    while True:
        conv = contexts + session.format_for_llm(sess)
        # In chat mode the first iteration carries the prompt the user just typed.
        # We append it now so it is part of the conversation.
        if chat_mode and session.message_count(sess) == 0:
            conv.append(user_msg)

        raw = llm_client.chat(settings, conv)
        if not raw:
            print("(empty response)")
            break

        parsed = protocol.parse_one_tool_call(raw)
        if parsed:
            # Give the user a short feedback line.
            name = parsed.get("tool")
            args_preview = str(parsed.get("arguments", {}))[:80]
            print(f"[tool: {name}] {args_preview}")

            result_str = _execute_tool_call(parsed)

            # Append tool round to session so future turns see it.
            assistant_msg = {"role": "assistant", "content": raw}
            tool_msg = {"role": "tool", "content": result_str}
            sess = session.append_message(sess, assistant_msg)
            sess = session.append_message(sess, tool_msg)

            # Give short feedback after tool execution.
            try:
                res_obj = json.loads(result_str)
            except json.JSONDecodeError:
                res_obj = {"ok": False, "error": "invalid JSON"}

            if res_obj.get("ok") is True:
                # For verbose tools show a snippet.
                if name == "read_file":
                    text = res_obj.get("content", "")
                    if text:
                        preview = text[:120].replace('\n', '↵')
                        print(f"  -> ok, {len(text)} chars: {preview}")
                    else:
                        print("  -> ok (empty)")
                elif name == "search_text":
                    lines = res_obj.get("matches", [])
                    print(f"  -> found {len(lines)} matches")
                elif name == "list_files":
                    items = res_obj.get("items", [])
                    print(f"  -> {len(items)} items")
                elif name == "run_shell":
                    out = res_obj.get("stdout", "")
                    exit_code = res_obj.get("returncode", 0)
                    if out:
                        preview = out[:100].replace('\n', '↵')
                        print(f"  -> exit {exit_code}, stdout: {preview}")
                    else:
                        print(f"  -> exit {exit_code}, no stdout")
                elif name == "write_file":
                    print(f"  -> written {len(res_obj.get('path',''))} bytes")
                else:
                    print(f"  -> ok")
            else:
                err = res_obj.get("error", "unknown")
                print(f"  -> error: {err}")

            continue

        # No tool call found — treat as final answer.
        answer = protocol.extract_final(raw)
        print(answer if answer.strip() else "(no final output)")

        # Persist final assistant message.
        final_msg = {"role": "assistant", "content": raw}
        sess = session.append_message(sess, final_msg)
        break

    session.save(sess)
    return sess["id"]


