import json
import os
import random
import sys
import time

import agent
import config
import llm_client
import session


def run_ask(args, settings):
    """Answer a single question."""
    agent.run_agent(settings, args.message, session_id=args.session_id)
    print()
    return 0


def run_chat(args, settings):
    """Interactive chat loop with session persistence."""
    session_id = args.session_id or session.generate_id()
    print(f"Session: {session_id}")
    print("Type /help for commands, /exit to quit.")
    while True:
        try:
            user_input = input(">>> ").strip()
        except (EOFError, KeyboardInterrupt):
            print()
            break

        if not user_input:
            continue

        if user_input.startswith("/"):
            handled = _handle_slash_command(user_input, settings, session_id)
            if handled == "exit":
                break
            continue

        agent.run_agent(settings, user_input, session_id=session_id, chat_mode=True)
        print()
    return 0


def run_sessions():
    """List ids and first user message of stored sessions."""
    entries = session.list_sessions()
    for entry in entries:
        print(f"{entry['id']}  {entry['first_message']}")
    return 0


def run_config(args):
    """Handle config subcommand."""
    if args.init_template:
        config.init_template()
        return 0

    if args.show:
        cfg = config.load_existing_config()
        if cfg is None:
            print("No local config found.")
        else:
            print(json.dumps(cfg, indent=2, ensure_ascii=False))
        return 0

    updates = {}
    if args.provider:
        updates["llm_provider"] = args.provider
    if args.api_key:
        updates["llm_api_key"] = args.api_key
    if args.base_url:
        updates["llm_base_url"] = args.base_url
    if args.model:
        updates["llm_model"] = args.model
    if args.headers_json:
        updates["llm_headers_json"] = args.headers_json
    if args.body_template_json:
        updates["llm_body_template_json"] = args.body_template_json
    if args.response_path:
        updates["llm_response_path"] = args.response_path
    if args.debug:
        updates["llm_debug"] = args.debug == "on"
    if args.git_bash_path:
        updates["git_bash_path"] = args.git_bash_path

    if not updates:
        print("No config options provided.")
        return 1

    config.update_local_config(updates)
    print("Config saved.")
    return 0


def _handle_slash_command(text, settings, session_id):
    parts = text.split()
    cmd = parts[0].lower()

    if cmd == "/help":
        print("Commands: /help /provider /session /sessions /files /read /search /config /clear /exit")
    elif cmd == "/provider":
        if len(parts) > 1:
            settings["llm_provider"] = parts[1]
            print(f"Provider set to {parts[1]} (this session only)")
        else:
            provider = settings.get("llm_provider", "openai_compatible")
            print(f"Provider: {provider}")
    elif cmd == "/session":
        sess = session.load_existing(session_id)
        if sess:
            print(f"Session: {sess['id']}")
            for msg in sess["messages"]:
                role = msg["role"]
                content = str(msg.get("content", ""))[:120].replace("\n", " ")
                print(f"  {role}: {content}")
        else:
            print("No session.")
    elif cmd == "/sessions":
        run_sessions()
    elif cmd == "/files":
        from app import files
        arg = parts[1] if len(parts) > 1 else "."
        result = files.list_files(arg, recursive=False)
        items = result.get("items", [])
        for item in items:
            print(f"  {item['name']}{'/' if item['is_dir'] else ''}")
        if not items:
            print("(empty)")
    elif cmd == "/read":
        from app import files
        if len(parts) < 2:
            print("Usage: /read <path>")
        else:
            result = files.read_file(parts[1])
            if result.get("ok"):
                print(result["content"])
            else:
                print(f"Error: {result.get('error')}")
    elif cmd == "/search":
        from app import files
        if len(parts) < 2:
            print("Usage: /search <keyword> [path]")
        else:
            keyword = parts[1]
            arg = parts[2] if len(parts) > 2 else "."
            result = files.search_text(keyword, arg)
            for match in result.get("matches", []):
                print(f"  {match['path']}:{match['line_number']}: {match['line']}")
    elif cmd == "/config":
        from app import config
        cfg = config.load_existing_config()
        if cfg is None:
            print("No local config found.")
        else:
            safe = {k: v for k, v in cfg.items() if "key" not in k}
            print(json.dumps(safe, indent=2, ensure_ascii=False))
    elif cmd == "/clear":
        session.delete_session(session_id)
        print("Session cleared.")
    elif cmd == "/exit":
        return "exit"
    else:
        print(f"Unknown command: {cmd}")
    return None


